/// <summary>
/// The <c>ETGSalesConfirmControllerExtension</c> class is the helper class for the associated SRS Report.
/// </summary>
class ETGSalesConfirmControllerExtension Extends SalesConfirmController
{
}

Method.Source:
public static ETGSalesConfirmControllerExtension construct()
{
    return new ETGSalesConfirmControllerExtension();
}

public static void main(Args _args)
{
    SrsReportRunController formLetterController = ETGSalesConfirmControllerExtension::construct();
    ETGSalesConfirmControllerExtension controller = formLetterController;
    controller.parmReportName(ssrsReportStr(ETGSalesConfirm, ETGSalesOrderReport));
    controller.parmArgs(_args);
    controller.startOperation();
}
